#if swift(>=5.8)
@_documentation(visibility: private)
#endif
public struct FfiConverterTypeSettingsService: FfiConverter {
    typealias FfiType = UInt64
    typealias SwiftType = SettingsService

    public static func lift(_ handle: UInt64) throws -> SettingsService {
        return SettingsService(unsafeFromHandle: handle)
    }

    public static func lower(_ value: SettingsService) -> UInt64 {
        return value.uniffiCloneHandle()
    }

    public static func read(from buf: inout (data: Data, offset: Data.Index)) throws -> SettingsService {
        let handle: UInt64 = try readInt(&buf)
        return try lift(handle)
    }

    public static func write(_ value: SettingsService, into buf: inout [UInt8]) {
        writeInt(&buf, lower(value))
    }
}


