/**
 * A handle to a running long operation. The only operation is honest cancellation; progress
 * and the terminal outcome arrive on the [`ImportListener`] the caller registered.
 */
public protocol TaskHandleProtocol: AnyObject, Sendable {
    
    /**
     * Requests cancellation of the operation. Idempotent and safe to call from any thread;
     * the operation stops at its next batch boundary and reports `Cancelled`.
     */
    func cancel() 
    
}
/**
 * A handle to a running long operation. The only operation is honest cancellation; progress
 * and the terminal outcome arrive on the [`ImportListener`] the caller registered.
 */
open class TaskHandle: TaskHandleProtocol, @unchecked Sendable {
    fileprivate let handle: UInt64

    /// Used to instantiate a [FFIObject] without an actual handle, for fakes in tests, mostly.
#if swift(>=5.8)
    @_documentation(visibility: private)
#endif
    public struct NoHandle {
        public init() {}
    }

    // TODO: We'd like this to be `private` but for Swifty reasons,
    // we can't implement `FfiConverter` without making this `required` and we can't
    // make it `required` without making it `public`.
#if swift(>=5.8)
    @_documentation(visibility: private)
#endif
    required public init(unsafeFromHandle handle: UInt64) {
        self.handle = handle
    }

    // This constructor can be used to instantiate a fake object.
    // - Parameter noHandle: Placeholder value so we can have a constructor separate from the default empty one that may be implemented for classes extending [FFIObject].
    //
    // - Warning:
    //     Any object instantiated with this constructor cannot be passed to an actual Rust-backed object. Since there isn't a backing handle the FFI lower functions will crash.
#if swift(>=5.8)
    @_documentation(visibility: private)
#endif
    public init(noHandle: NoHandle) {
        self.handle = 0
    }

#if swift(>=5.8)
    @_documentation(visibility: private)
#endif
    public func uniffiCloneHandle() -> UInt64 {
        return try! rustCall { uniffi_core_api_fn_clone_taskhandle(self.handle, $0) }
    }
    // No primary constructor declared for this class.

    deinit {
        if handle == 0 {
            // Mock objects have handle=0 don't try to free them
            return
        }

        try! rustCall { uniffi_core_api_fn_free_taskhandle(handle, $0) }
    }

    

    
    /**
     * Requests cancellation of the operation. Idempotent and safe to call from any thread;
     * the operation stops at its next batch boundary and reports `Cancelled`.
     */
open func cancel()  {try! rustCall() {
        uniffiCallStatus in
    uniffi_core_api_fn_method_taskhandle_cancel(
            self.uniffiCloneHandle(),uniffiCallStatus
    )
}
}
    

    
}


