/**
 * A store the host implements over its platform secure storage.
 *
 * Foreign-implemented only (the core never provides an implementation across the boundary),
 * so this is a UniFFI callback interface. Every method may be called from any core thread.
 */
public protocol SecretStore: AnyObject, Sendable {
    
    /**
     * Retrieves the secret value stored under `key`, or `None` if there is none.
     *
     * # Errors
     * Returns [`ApiError`] if the secure store is unavailable.
     */
    func get(key: String) throws  -> String?
    
    /**
     * Stores `value` under `key`, replacing any existing value.
     *
     * # Errors
     * Returns [`ApiError`] if the secure store rejects the write.
     */
    func set(key: String, value: String) throws 
    
    /**
     * Deletes the secret under `key` (idempotent).
     *
     * # Errors
     * Returns [`ApiError`] if the secure store rejects the delete.
     */
    func delete(key: String) throws 
    
}


// Put the implementation in a struct so we don't pollute the top-level namespace
fileprivate struct UniffiCallbackInterfaceSecretStore {

    // Create the VTable using a series of closures.
    // Swift automatically converts these into C callback functions.
    //
    // Store the vtable directly.
    static let vtable: UniffiVTableCallbackInterfaceSecretStore = UniffiVTableCallbackInterfaceSecretStore(
        uniffiFree: { (uniffiHandle: UInt64) -> () in
            do {
                try FfiConverterCallbackInterfaceSecretStore.handleMap.remove(handle: uniffiHandle)
            } catch {
                print("Uniffi callback interface SecretStore: handle missing in uniffiFree")
            }
        },
        uniffiClone: { (uniffiHandle: UInt64) -> UInt64 in
            do {
                return try FfiConverterCallbackInterfaceSecretStore.handleMap.clone(handle: uniffiHandle)
            } catch {
                fatalError("Uniffi callback interface SecretStore: handle missing in uniffiClone")
            }
        },
        get: { (
            uniffiHandle: UInt64,
            key: RustBuffer,
            uniffiOutReturn: UnsafeMutablePointer<RustBuffer>,
            uniffiCallStatus: UnsafeMutablePointer<RustCallStatus>
        ) in
            let makeCall = {
                () throws -> String? in
                guard let uniffiObj = try? FfiConverterCallbackInterfaceSecretStore.handleMap.get(handle: uniffiHandle) else {
                    throw UniffiInternalError.unexpectedStaleHandle
                }
                return try uniffiObj.get(
                     key: try FfiConverterString.lift(key)
                )
            }

            
            let writeReturn = { uniffiOutReturn.pointee = FfiConverterOptionString.lower($0) }
            uniffiTraitInterfaceCallWithError(
                callStatus: uniffiCallStatus,
                makeCall: makeCall,
                writeReturn: writeReturn,
                lowerError: FfiConverterTypeApiError_lower
            )
        },
        set: { (
            uniffiHandle: UInt64,
            key: RustBuffer,
            value: RustBuffer,
